    expect(result.content, contains('Line 1'));
    expect(result.content, contains('Line 2'));
  });

  test('Backticks code block style uses triple backtick fences', () {
    final result = convert('<pre><code class="language-js">console.log(\'hi\');</code></pre>', '{"codeBlockStyle":"Backticks"}');
