  test('Tildes code block style uses triple tilde fences', () {
    final result = convert('<pre><code>some code</code></pre>', '{"codeBlockStyle":"Tildes"}');
    expect(result.content, contains('~~~'));
    expect(result.content, contains('some code'));
  });

  test('Default code language annotation on blocks without lang attribute', () {
