    expect(result.content, contains('def hello'));
  });

  test('Block elements treated as inline', () {
    final result = convert('<p>One</p><p>Two</p>', '{"convertAsInline":true}');
    expect(result.content, contains('One'));
    expect(result.content, contains('Two'));
  });

  test('Debug mode enabled does not crash and produces output', () {
    final result = convert('<p>Debug test</p>', '{"debug":true}');
