    expect(result.content, contains('https://example.com'));
  });

  test('UTF-8 encoding hint for special characters', () {
    final result = convert('<p>Café naïve résumé</p>', '{"encoding":"utf-8"}');
    expect(result.content, isNotEmpty);
  });

  test('ASCII Markdown characters are escaped when escapeAscii is true', () {
    final result = convert('<p>Text with # hash and [brackets] and * star</p>', '{"escapeAscii":true}');
    expect(result.content, contains('Text'));
    expect(result.content, contains('hash'));
    expect(result.content, contains('brackets'));
    expect(result.content, contains('star'));
  });

  test('escape_asterisks option escapes asterisks in plain text', () {
    final result = convert('<p>Use 2*3 = 6 in math.</p>', '{"escapeAsterisks":true}');
    expect(result.content, isNotEmpty);
    expect(result.content, contains('2'));
    expect(result.content, contains('3'));
    expect(result.content, contains('6'));
  });

  test('escape_misc option escapes miscellaneous markdown characters', () {
