    expect(result.content, isNotEmpty);
    expect(result.content, contains('Use'));
    expect(result.content, contains('and'));
    expect(result.content, contains('in text.'));
  });

  test('escape_underscores option escapes underscores in plain text', () {
    final result = convert('<p>The variable_name is defined.</p>', '{"escapeUnderscores":true}');
