    expect(result.content, contains('variable'));
    expect(result.content, contains('name'));
    expect(result.content, contains('defined.'));
  });

  test('Elements matching CSS attribute selector are excluded entirely', () {
    final result = convert('<body><div role="complementary">Sidebar</div><p>Primary text</p></body>', '{"excludeSelectors":["[role=\'complementary\']"]}');
    expect(result.content, contains('Primary text'));
    expect(result.content, isNot(contains('Sidebar')));
  });

  test('Elements matching CSS class selector are excluded entirely', () {
    final result = convert('<body><div class="cookie-banner">Accept cookies</div><p>Main content</p></body>', '{"excludeSelectors":[".cookie-banner"]}');
    expect(result.content, contains('Main content'));
    expect(result.content, isNot(contains('cookies')));
  });

  test('Empty exclude_selectors list does not affect output', () {
    final result = convert('<p>Hello world</p>', '{"excludeSelectors":[]}');
    expect(result.content, contains('Hello world'));
  });

  test('Elements matching CSS id selector are excluded entirely', () {
