    expect(result.content, contains('Article text'));
    expect(result.content, isNot(contains('Buy stuff')));
  });

  test('Multiple CSS selectors each exclude their matched elements', () {
    final result = convert('<body><nav class="nav">Menu</nav><p>Content</p><footer>Footer</footer></body>', '{"excludeSelectors":[".nav","footer"]}');
    expect(result.content, contains('Content'));
    expect(result.content, isNot(contains('Menu')));
    expect(result.content, isNot(contains('Footer')));
  });

  test('All descendants of excluded elements are dropped', () {
